import logging
import os
import json
from typing import List
from azure.functions import TimerRequest
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.eventgrid.models import EventGridEvent
from azure.identity import DefaultAzureCredential

# Initialize logging
logger = logging.getLogger('AzureFunction')

def main(mytimer: TimerRequest):
    try:
        # Initialize managed identity credential
        credential = DefaultAzureCredential()
        
        # Get connection strings from environment variables
        blob_connection_string = os.environ.get('BLOB_STORAGE_CONNECTION_STRING')
        cosmos_endpoint = os.environ.get('COSMOS_DB_ENDPOINT')
        cosmos_key = os.environ.get('COSMOS_DB_KEY')
        event_grid_endpoint = os.environ.get('EVENT_GRID_ENDPOINT')
        
        # Initialize clients
        blob_service_client = BlobServiceClient(
            account_url=blob_connection_string,
            credential=credential
        )
        
        cosmos_client = CosmosClient(
            cosmos_endpoint,
            credential=credential
        )
        
        event_grid_client = EventGridPublisherClient(
            endpoint=event_grid_endpoint,
            credential=credential
        )
        
        # Process blob storage
        container_client = blob_service_client.get_container_client("input-container")
        blob_list = container_client.list_blobs()
        
        results = []
        for blob in blob_list:
            if blob.name.endswith('.json'):
                blob_client = container_client.get_blob_client(blob.name)
                data = blob_client.download_blob().readall()
                processed_data = process_data(json.loads(data))
                results.append(processed_data)
                
                # Write to Cosmos DB
                database = cosmos_client.get_database_client("mydatabase")
                container = database.get_container_client("mycontainer")
                container.upsert_item(processed_data)
                
                # Send notification via Event Grid
                event = EventGridEvent(
                    event_type="FileProcessed",
                    subject=f"file/{blob.name}",
                    data=processed_data,
                    data_version="1.0"
                )
                event_grid_client.send([event])
        
        logger.info(f"Processed {len(results)} files")
        
    except Exception as e:
        logger.error(f"Error in function: {str(e)}")
        raise

